fun solve(nums: Array<Long>, k: Long): Long {
    if (nums.size == 1) return 0L

    // Sort the array to easily find min and max in any subarray
    val sorted = nums.sorted()

    // Use a sliding window approach to find the smallest window where max <= k * min
    var left = 0
    var minRemove = Long.MAX_VALUE

    for (right in 0 until sorted.size) {
        // Expand the window to the right
        while (left <= right && sorted[right].toLong() > k * sorted[left]) {
            left++
        }

        // Check if the current window is valid
        if (left <= right) {
            // The number of elements to remove is the total elements minus the window size
            val remove = sorted.size - (right - left + 1)
            minRemove = min(minRemove, remove)
        }
    }

    return minRemove
}
