fun solve(nums: Array<Long>, k: Long): Long {
    if (nums.size == 1) return 0L

    // Sort the array to easily find min and max in subarrays
    val sorted = nums.sorted()

    // Initialize the result to the maximum possible removals (all elements except one)
    var minRemovals = nums.size - 1

    // Try all possible subarrays of size >= 1
    for (i in 0 until sorted.size) {
        // Start of the subarray
        val start = i
        // End of the subarray (we try all possible end positions)
        for (j in start until sorted.size) {
            // Check if the subarray from start to j is balanced
            val minVal = sorted[start]
            val maxVal = sorted[j]
            if (maxVal <= minVal * k) {
                // Calculate the number of elements to remove
                val removals = nums.size - (j - start + 1)
                minRemovals = min(minRemovals, removals)
                break // No need to check longer subarrays starting at i
            }
        }
    }

    return minRemovals
}
